   364→/// Build and print the file-touch bitmap for a heat.
   365→///
   366→/// Uses shared query routines from jjrq_query to get file touches,
   367→/// then formats as a bitmap with columns per pace and rows per file,
   368→/// grouped by identical touch patterns.
   369→fn zjjrpd_print_file_bitmap(firemark: &Firemark, heat: &Heat) {
   370→    let touches = match jjrq_file_touches_for_heat(firemark.jjrf_as_str()) {
   371→        Ok(t) => t,
   372→        Err(e) => {
   373→            eprintln!("jjx_show: error getting file touches: {}", e);
   374→            return;
   375→        }
   376→    };
   377→
   378→    let has_heat_level = !touches.heat_files.is_empty();
   379→
   380→    // Build pace columns: only paces with commits, in heat order
   381→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
   382→    for coronet_key in &heat.order {
   383→        if !touches.coronets_with_commits.contains(coronet_key) {
   384→            continue;
   385→        }
   386→        if let Some(pace) = heat.paces.get(coronet_key) {
   387→            if let Some(tack) = pace.tacks.first() {
   388→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
   389→                if let Some(ch) = raw.chars().last() {
   390→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
   391→                }
   392→            }
   393→        }
   394→    }
   395→
   396→    // Map coronet_display -> column index
   397→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
   398→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
   399→        coronet_to_col.insert(coronet_display.clone(), idx);
   400→    }
   401→
   402→    let heat_col_idx = pace_columns.len();
   403→    let total_cols = if has_heat_level { heat_col_idx + 1 } else { heat_col_idx };
   404→
   405→    // Build file -> touch vector from the shared query result
   406→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
   407→
   408→    for (coronet, files) in &touches.pace_files {
   409→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
   410→            for filename in files {
   411→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   412→                if col_idx < row.len() {
   413→                    row[col_idx] = true;
   414→                }
   415→            }
   416→        }
   417→    }
   418→
   419→    if has_heat_level {
   420→        for filename in &touches.heat_files {
   421→            let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   422→            if heat_col_idx < row.len() {
   423→                row[heat_col_idx] = true;
   424→            }
   425→        }
   426→    }
   427→
   428→    if file_touches_map.is_empty() {
   429→        println!("File-touch bitmap: (no work file changes)");
   430→        return;
   431→    }
   432→
   433→    // Group files by identical touch pattern
   434→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
   435→    for (filename, pattern) in &file_touches_map {
   436→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
   437→    }
   438→
   439→    for files in pattern_groups.values_mut() {
   440→        files.sort();
   441→    }
   442→
   443→    // Print header
   444→    println!("File-touch bitmap (x = pace commit touched file):");
   445→    println!();
   446→
   447→    // Print vertical legend
   448→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
   449→        println!("  {} {} {}", i + 1, ch, silks);
   450→    }
   451→    if has_heat_level {
   452→        println!("  {} * heat-level", pace_columns.len() + 1);
   453→    }
   454→    println!();
   455→
   456→    // Print column header line (terminal chars aligned with bitmap positions)
   457→    let mut header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
   458→    if has_heat_level {
   459→        header_chars.push('*');
   460→    }
   461→    let header_line: String = header_chars.iter().collect();
   462→    println!("{}", header_line);
   463→
   464→    // Sort patterns: more touches first, then lexicographic
   465→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
   466→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
   467→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
   468→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
   469→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
   470→    });
   471→
   472→    for (pattern, files) in &sorted_patterns {
   473→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
   474→        println!("{} {}", bitmap, files.join(", "));
   475→    }
   476→}
