   478→/// Helper to convert PaceState to display string
   479→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
   480→    match state {
   481→        PaceState::Rough => "rough",
   482→        PaceState::Bridled => "bridled",
   483→        PaceState::Complete => "complete",
   484→        PaceState::Abandoned => "abandoned",
   485→    }
   486→}
