   508→/// Print commit swim lanes for a heat: paces × commits matrix.
   509→///
   510→/// Shows when work happened on each pace and how work interleaved.
   511→/// Called after file-touch bitmap in heat parade.
   512→fn zjjrpd_print_commit_swimlanes(firemark: &Firemark, heat: &Heat) {
   513→    let rein_args = jjrs_ReinArgs {
   514→        firemark: firemark.jjrf_as_str().to_string(),
   515→        limit: 10000,
   516→    };
   517→
   518→    let entries = match jjrs_get_entries(&rein_args) {
   519→        Ok(e) => e,
   520→        Err(e) => {
   521→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
   522→            return;
   523→        }
   524→    };
   525→
   526→    if entries.is_empty() {
   527→        return;
   528→    }
   529→
   530→    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
   531→    let total_commits = entries.len();
   532→    let max_commits: usize = 35;
   533→    let truncated = total_commits > max_commits;
   534→    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
   535→        .iter()
   536→        .take(max_commits)
   537→        .collect::<Vec<_>>()
   538→        .into_iter()
   539→        .rev()
   540→        .collect();
   541→
   542→    // Build pace rows: ordered by first chronological appearance
